// ============================================================
// 配置常量
// ============================================================

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000/api';

const STORAGE_TOKEN_KEY = 'auth_token';
const STORAGE_USER_KEY = 'user_info';

// ============================================================
// 工具函数
// ============================================================

/** 获取存储的 Token */
export function getStoredToken(): string | null {
  return localStorage.getItem(STORAGE_TOKEN_KEY);
}

/** 存储 Token */
export function storeToken(token: string): void {
  localStorage.setItem(STORAGE_TOKEN_KEY, token);
}

/** 清除 Token */
export function clearToken(): void {
  localStorage.removeItem(STORAGE_TOKEN_KEY);
  localStorage.removeItem(STORAGE_USER_KEY);
}

/** 获取存储的用户信息 */
export function getStoredUser(): User | null {
  const userStr = localStorage.getItem(STORAGE_USER_KEY);
  if (!userStr) return null;
  try {
    return JSON.parse(userStr);
  } catch {
    return null;
  }
}

/** 存储用户信息 */
export function storeUser(user: User): void {
  localStorage.setItem(STORAGE_USER_KEY, JSON.stringify(user));
}

/** 构建查询字符串 */
function buildQueryString(params: Record<string, string | number | boolean | undefined>): string {
  const searchParams = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value !== undefined && value !== null && value !== '') {
      searchParams.append(key, String(value));
    }
  });
  const query = searchParams.toString();
  return query ? `?${query}` : '';
}

// ============================================================
// HTTP 请求核心函数
// ============================================================

/** HTTP 请求封装 */
async function request<T>(
  method: string,
  endpoint: string,
  body?: unknown,
  config: ApiRequestConfig = {}
): Promise<T> {
  const token = getStoredToken();

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    ...(token && { Authorization: `Bearer ${token}` }),
    ...config.headers,
  };

  const url = `${API_BASE_URL}${endpoint}`;
  const queryString = config.params 
    ? buildQueryString(config.params as Record<string, string | number | boolean | undefined>)
    : '';

  const options: RequestInit = {
    method,
    headers,
  };

  if (body && method !== 'GET') {
    options.body = JSON.stringify(body);
  }

  try {
    const response = await fetch(`${url}${queryString}`, options);

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({
        code: 'UNKNOWN_ERROR',
        message: `HTTP ${response.status}: ${response.statusText}`,
      }));
      throw new Error(errorData.message || errorData.code || '请求失败');
    }

    return await response.json();
  } catch (error) {
    if (error instanceof Error) {
      throw error;
    }
    throw new Error('网络请求失败，请检查网络连接');
  }
}

// ============================================================
// API Client 实例
// ============================================================

const apiClient = {
  get: <T>(url: string, config?: ApiRequestConfig) => 
    request<T>('GET', url, undefined, config),

  post: <T>(url: string, body?: unknown, config?: ApiRequestConfig) => 
    request<T>('POST', url, body, config),

  put: <T>(url: string, body?: unknown, config?: ApiRequestConfig) => 
    request<T>('PUT', url, body, config),

  delete: <T>(url: string, config?: ApiRequestConfig) => 
    request<T>('DELETE', url, undefined, config),
};

// ============================================================
// 认证相关 API
// ============================================================

export const authApi = {
  /** 用户登录 */
  login: async (data: LoginRequest): Promise<AuthResponse> => {
    const response = await apiClient.post<AuthResponse>('/auth/login', data);
    storeToken(response.token);
    storeUser(response.user);
    return response;
  },

  /** 用户注册 */
  register: async (data: RegisterRequest): Promise<AuthResponse> => {
    const response = await apiClient.post<AuthResponse>('/auth/register', data);
    storeToken(response.token);
    storeUser(response.user);
    return response;
  },

  /** 获取当前用户信息 */
  getCurrentUser: async (): Promise<User> => {
    return apiClient.get<User>('/auth/me');
  },

  /** 用户登出 */
  logout: (): void => {
    clearToken();
  },
};

