  /** 获取热门商品 */
  getFeaturedProducts: async (limit: number = 8): Promise<Product[]> => {
    return apiClient.get<Product[]>('/products/featured', {
      params: { limit },
    });
  },

  /** 获取所有分类 */
  getCategories: async (): Promise<string[]> => {
