// ============================================================
// 电商平台 - TypeScript 类型定义
// ============================================================
// 本文件按关联源文件分组，每个文件使用 [FILE: <path>] 标记
// 通用类型使用 [COMMON] 标记
// ============================================================

// ============================================================
// [COMMON] 通用类型 - 跨文件共享
// ============================================================

/** API 错误响应 */
export interface ApiError {
  code: string;
  message: string;
}

/** 通用成功响应 */
export interface SuccessResponse {
  success: true;
  message: string;
}

/** 分页元数据 */
export interface PaginationMeta {
  page: number;
  pageSize: number;
  total: number;
  totalPages: number;
}

// ============================================================
// [FILE: src/types/index.ts] - 核心数据模型
// ============================================================

/** 用户信息 */
export interface User {
  id: number;
  username: string;
  email: string;
  createdAt: string;
}

/** 商品信息 */
export interface Product {
  id: number;
  name: string;
  description: string;
  price: number;
  image: string;
  category: string;
  stock: number;
  sales: number;
  createdAt: string;
}

/** 购物车项（含商品详情） */
export interface CartItem {
  id: number;
  userId: number;
  productId: number;
  quantity: number;
  product: Product;
}

/** 购物��� */
export interface Cart {
  items: CartItem[];
  total: number;
}

/** 订单 */
export interface Order {
  id: number;
  userId: number;
  status: OrderStatus;
  total: number;
  items: OrderItem[];
  createdAt: string;
  updatedAt: string;
}

/** 订单项 */
export interface OrderItem {
  id: number;
  orderId: number;
  productId: number;
  quantity: number;
  price: number;
  product: Product;
}

/** 订单状态枚举 */
export type OrderStatus = 'pending' | 'paid' | 'shipped' | 'delivered' | 'cancelled';

